mapper.select:
select 
from t_piamom_moment a
left join t_member m on m.id = a.user_id


    order by ${orderBy}
    order by a.created_at desc, a.id desc

limit #{pageNo}, #{pageSize}

mapper.update:
update t_piamom_moment m
set m.like_count = (
    select count(1) from t_piamom_moment_like l where l.moment_id = #{id}
),
    m.updated_at = now()
where m.id = #{id}

update t_piamom_moment m
set m.comment_count = (
    select count(1) from t_piamom_moment_comment c where c.moment_id = #{id}
),
    m.updated_at = now()
where m.id = #{id}
